function ensureAdvancedFields(){
  if(!db.vehicles) db.vehicles=[]; if(!db.fuel) db.fuel=[]; if(!db.maintenance) db.maintenance=[];
  db.vehicles.forEach(v=>{ if(v.targetConso===undefined) v.targetConso=""; if(v.comment===undefined) v.comment=""; });
  db.fuel.forEach(f=>{ if(!f.id) f.id=uid(); if(!f.week && f.date){ f.week=weekKey(f.date); f.month=monthKey(f.date); f.year=yearKey(f.date); } });
}
function normPlateText(s){return String(s||"").toUpperCase().replace(/[^A-Z0-9]/g,"");}
function matchPlate(plate,q){const p=normPlateText(plate), x=normPlateText(q); return !x || p.includes(x) || String(plate||"").toUpperCase().includes(String(q||"").toUpperCase());}
function filteredFuelPlateOptions(q=""){return db.vehicles.filter(v=>v.status!="HS").filter(v=>matchPlate(v.plate,q)).map(v=>`<option>${v.plate}</option>`).join("");}
function installPlateSearchFuel(){const f=document.getElementById("fuelForm"), s=document.getElementById("plateSearchFuel"); if(!f||!s||s.dataset.installed==="1")return; s.dataset.installed="1"; const sel=f.elements.plate; s.addEventListener("input",()=>{const old=sel.value; sel.innerHTML=filteredFuelPlateOptions(s.value); if([...sel.options].some(o=>o.value===old)) sel.value=old; else if(sel.options.length===1){sel.selectedIndex=0; sel.dispatchEvent(new Event("change"));}});}
function getLastKmEndForPlateAndType(plate,type,excludeId=""){const tickets=(db.fuel||[]).filter(f=>f.plate===plate&&f.type===type&&f.kmEnd!==""&&f.kmEnd!==undefined&&f.kmEnd!==null&&f.id!==excludeId).sort((a,b)=>{const d=String(b.date||"").localeCompare(String(a.date||"")); if(d!==0)return d; return String(b.id||"").localeCompare(String(a.id||""));}); return tickets.length?tickets[0].kmEnd:"";}
function autoFillKmStartFromPlateAndType(){const form=document.getElementById("fuelForm"); if(!form)return; const plate=form.elements.plate.value, type=form.elements.type.value, id=form.elements.id?form.elements.id.value:""; if(!plate||!type)return; const last=getLastKmEndForPlateAndType(plate,type,id); if(last!==""&&(form.elements.kmStart.value===""||form.dataset.autoKmStart==="1")){form.elements.kmStart.value=last; form.dataset.autoKmStart="1";}}
function installFuelAutoKmAdvanced(){const form=document.getElementById("fuelForm"); if(!form||form.dataset.autoKmAdvancedInstalled==="1")return; form.dataset.autoKmAdvancedInstalled="1"; form.dataset.autoKmStart="1"; form.elements.plate.addEventListener("change",()=>{form.elements.kmStart.value=""; form.dataset.autoKmStart="1"; autoFillKmStartFromPlateAndType();}); form.elements.type.addEventListener("change",()=>{form.elements.kmStart.value=""; form.dataset.autoKmStart="1"; autoFillKmStartFromPlateAndType();}); form.elements.kmStart.addEventListener("input",()=>{form.dataset.autoKmStart="0";}); form.elements.date.addEventListener("change",()=>autoFillKmStartFromPlateAndType());}
function documentAlertsForVehicle(v){const arr=[], ct=daysUntil(v.ctDate), as=daysUntil(v.insuranceDate); if(ct!==null){if(ct<0)arr.push({status:"Urgent",text:`${v.plate} : contrôle technique expiré depuis ${Math.abs(ct)} jours.`,category:"document"}); else if(ct<=30)arr.push({status:"Surveiller",text:`${v.plate} : contrôle technique expire dans ${ct} jours.`,category:"document"});} if(as!==null){if(as<0)arr.push({status:"Urgent",text:`${v.plate} : assurance expirée depuis ${Math.abs(as)} jours.`,category:"document"}); else if(as<=30)arr.push({status:"Surveiller",text:`${v.plate} : assurance expire dans ${as} jours.`,category:"document"});} return arr;}
function vidangeAlertAdvanced(v){const currentKm=n(v.km); const vid=getLatestVidangeByPlate(v.plate); const nextKm=vid?n(vid.nextKm):n(v.nextServiceKm); if(!currentKm||!nextKm)return null; const rem=nextKm-currentKm; if(rem<0)return{status:"Urgent",text:`Vidange dépassée de ${Math.abs(rem)} km`,category:"maintenance"}; if(rem<=2000)return{status:"Surveiller",text:`Vidange à prévoir dans ${rem} km`,category:"maintenance"}; return null;}
function selectedAlertWeek(){const i=document.getElementById("alertWeekFilter"); return i&&i.value?i.value:currentWeek();}
function allAlertsAdvanced(){ensureAdvancedFields(); const arr=[], wk=selectedAlertWeek(); db.vehicles.forEach(v=>{if(v.status==="HS")return; const va=vidangeAlertAdvanced(v); if(va)arr.push({status:va.status,text:`${v.plate} : ${va.text}.`,category:"maintenance"}); documentAlertsForVehicle(v).forEach(x=>arr.push(x)); const done=(db.fuel||[]).some(f=>f.plate===v.plate&&f.type==="AdBlue"&&(f.week||weekKey(f.date))===wk); if(!done)arr.push({status:"Surveiller",text:`${v.plate} : AdBlue non saisi pour la semaine ${wk}.`,category:"adblue"});}); db.stock.forEach(s=>{if(n(s.qty)<=n(s.min))arr.push({status:"Urgent",text:`Stock : ${s.name} à commander. Stock actuel : ${n(s.qty)}.`,category:"stock"});}); return arr;}
