function renderMaintenance(){const q=document.getElementById("maintFilterPlate")?.value||"", d=document.getElementById("maintFilterDate")?.value||"", t=document.getElementById("maintFilterType")?.value||""; const data=(db.maintenance||[]).filter(m=>(!q||matchPlate(m.plate,q))&&(!d||m.date===d)&&(!t||m.type===t)); table("maintenanceTable", ["Date","Plaque","Km","Type","Description","HT","TTC","Facture","Prochaine vidange","Km prochaine vidange","Pièces utilisées","Commentaire","Actions"], data.map(m=>{const idx=db.maintenance.indexOf(m); const pcs=normalizeMaintenancePieces(m).map(p=>`${p.piece} x ${p.qty}`).join("<br>"); return [m.date,m.plate,m.km,m.type,m.description,m.costHT,m.costTTC,m.invoice,m.nextDate,m.nextKm,pcs,m.comment,`<button class="smallbtn edit-maint" data-index="${idx}">Modifier</button><button class="smallbtn redbtn delete-maint" data-index="${idx}">Supprimer</button>`];}));}
function renderAlerts(){if(!document.getElementById("alertWeekFilter")){const sec=document.getElementById("alerts"), list=document.getElementById("alertsList"); if(sec&&list){const div=document.createElement("div"); div.className="box"; div.innerHTML=`<h3>Filtre semaine AdBlue</h3><form class="gridform compact" onsubmit="return false"><input id="alertWeekFilter" placeholder="Semaine ex: 2026-S24" value="${currentWeek()}" oninput="renderAlerts()"><button type="button" onclick="document.getElementById('alertWeekFilter').value=currentWeek();renderAlerts()">Semaine actuelle</button></form><p class="hint">L’alerte AdBlue affiche uniquement les camions qui n’ont pas encore une saisie AdBlue sur la semaine choisie.</p>`; sec.insertBefore(div,list);}}
 const a=allAlertsAdvanced(), el=document.getElementById("alertsList"); if(el)el.innerHTML=a.length?a.map(x=>`<div class="alert ${x.status}"><b>${x.status==="Surveiller"?"À surveiller":x.status}</b> — ${x.text}</div>`).join(""):'<div class="alert OK">Aucune alerte.</div>'; const dash=document.getElementById("dashboardAlerts"); if(dash){const imp=importantAlertsDashboard(); dash.innerHTML=imp.length?imp.map(x=>`<div class="alert ${x.status}"><b>${x.status==="Surveiller"?"À surveiller":x.status}</b> — ${x.text}</div>`).join(""):'<div class="alert OK">Aucune alerte importante.</div>';}}
function periodKeyAdvanced(f,p){if(p==="day")return f.date;if(p==="week")return f.week||weekKey(f.date);if(p==="month")return f.month||monthKey(f.date);return f.year||yearKey(f.date);}
function buildReportRows(){normalizeFuelDates(); const period=document.getElementById("reportPeriod")?.value||"week", plate=document.getElementById("reportPlate")?.value||"", start=document.getElementById("reportStartDate")?.value||"", end=document.getElementById("reportEndDate")?.value||"", only=!!document.getElementById("reportOnlyOver")?.checked; const groups={}; (db.fuel||[]).forEach(f=>{if(plate&&f.plate!==plate)return;if(start&&f.date<start)return;if(end&&f.date>end)return; const key=periodKeyAdvanced(f,period)+"|"+f.plate; if(!groups[key])groups[key]={period:key.split("|")[0],plate:f.plate,km:0,gasL:0,gasCost:0,adbL:0,adbCost:0,totalCost:0,target:0,over:false,conso:0}; const g=groups[key]; if(f.type==="Gasoil"){g.gasL+=n(f.totalLiters);g.gasCost+=n(f.totalCost);g.km+=n(f.kmDone);}else{g.adbL+=n(f.totalLiters);g.adbCost+=n(f.totalCost);} g.totalCost+=n(f.totalCost);}); let rows=Object.values(groups).map(r=>{const v=(db.vehicles||[]).find(x=>x.plate===r.plate); r.target=n(v?.targetConso); r.conso=r.km>0?r.gasL/r.km*100:0; r.over=r.target>0&&r.conso>r.target; return r;}); if(only)rows=rows.filter(r=>r.over); const sort=document.getElementById("reportSort")?.value||"period_desc"; if(sort==="conso_desc")rows.sort((a,b)=>b.conso-a.conso); else if(sort==="conso_asc")rows.sort((a,b)=>a.conso-b.conso); else if(sort==="cost_desc")rows.sort((a,b)=>b.totalCost-a.totalCost); else rows.sort((a,b)=>String(b.period).localeCompare(String(a.period))||a.plate.localeCompare(b.plate)); return rows;}
function renderReports(){lastReportRows=buildReportRows(); const totals=lastReportRows.reduce((acc,r)=>{acc.km+=n(r.km);acc.gasL+=n(r.gasL);acc.gasCost+=n(r.gasCost);acc.adbL+=n(r.adbL);acc.adbCost+=n(r.adbCost);acc.totalCost+=n(r.totalCost);return acc;},{km:0,gasL:0,gasCost:0,adbL:0,adbCost:0,totalCost:0}); const avg=totals.km>0?totals.gasL/totals.km*100:0; document.getElementById("reportCards").innerHTML=[["Km total",totals.km.toFixed(0)+" km"],["Gasoil total",totals.gasL.toFixed(1)+" L"],["Coût gasoil",totals.gasCost.toFixed(2)+" €"],["AdBlue total",totals.adbL.toFixed(1)+" L"],["Coût AdBlue",totals.adbCost.toFixed(2)+" €"],["Coût total",totals.totalCost.toFixed(2)+" €"],["Conso moyenne",avg.toFixed(2)+" L/100"],["Surconsommations",lastReportRows.filter(r=>r.over).length]].map(c=>`<div class="card">${c[0]}<b>${c[1]}</b></div>`).join(""); table("reportTable",["Période","Plaque","Km","Gasoil L","Gasoil €","AdBlue L","AdBlue €","Coût total","Conso L/100","Conso max","Alerte"],lastReportRows.map(r=>[r.period,r.plate,n(r.km).toFixed(0),n(r.gasL).toFixed(1),n(r.gasCost).toFixed(2)+" €",n(r.adbL).toFixed(1),n(r.adbCost).toFixed(2)+" €",n(r.totalCost).toFixed(2)+" €",r.km>0?`<span class="${r.over?'over':''}">${r.conso.toFixed(2)}</span>`:"",r.target>0?r.target.toFixed(2):"",r.over?'<span class="status Urgent">Surconsommation</span>':'<span class="status OK">OK</span>']));}
function exportReportCSV(){if(!lastReportRows||!lastReportRows.length)renderReports(); const headers=["Période","Plaque","Km","Gasoil L","Gasoil €","AdBlue L","AdBlue €","Coût total","Conso L/100","Conso max","Alerte"]; const rows=lastReportRows.map(r=>[r.period,r.plate,n(r.km).toFixed(0),n(r.gasL).toFixed(1),n(r.gasCost).toFixed(2),n(r.adbL).toFixed(1),n(r.adbCost).toFixed(2),n(r.totalCost).toFixed(2),r.conso?r.conso.toFixed(2):"",r.target?r.target.toFixed(2):"",r.over?"Surconsommation":"OK"]); const csv=[headers,...rows].map(row=>row.map(v=>`"${String(v).replaceAll('"','""')}"`).join(";")).join("\n"); const blob=new Blob([csv],{type:"text/csv;charset=utf-8"}); const a=document.createElement("a"); a.href=URL.createObjectURL(blob); a.download="bilan_consommation.csv"; a.click();}
function vehicleStatus(v){if(v.status==="HS")return"Urgent"; const docs=documentAlertsForVehicle(v); if(docs.some(x=>x.status==="Urgent"))return"Urgent"; if(docs.some(x=>x.status==="Surveiller"))return"Surveiller"; const va=vidangeAlertAdvanced(v); if(va)return va.status; return"OK";}
function renderVehicles(){ensureAdvancedFields(); table("vehiclesTable",["Plaque","Marque","Modèle","Année","Km actuel","Dernier entretien","Km dernier","Prochaine vidange","Km prochaine vidange","CT expire","Assurance expire","Conso max","Commentaire","Statut auto","Action"],db.vehicles.map((v,idx)=>[v.plate,v.brand,v.model,v.year,v.km,v.lastServiceDate,v.lastServiceKm,v.nextServiceDate,v.nextServiceKm,v.ctDate,v.insuranceDate,v.targetConso||"",v.comment||"",`<span class="status ${vehicleStatus(v)}">${vehicleStatus(v)==="Surveiller"?"À surveiller":vehicleStatus(v)}</span>`,`<button class="smallbtn edit-vehicle" data-index="${idx}">Modifier</button>`]));}
function renderDashboard(){normalizeFuelDates(); const active=db.vehicles.filter(v=>v.status!=="HS").length, hs=db.vehicles.filter(v=>v.status==="HS").length, wk=currentWeek(), gas=db.fuel.filter(f=>(f.week||weekKey(f.date))===wk&&f.type==="Gasoil"), adb=db.fuel.filter(f=>(f.week||weekKey(f.date))===wk&&f.type==="AdBlue"), km=gas.reduce((s,f)=>s+n(f.kmDone),0), gasL=gas.reduce((s,f)=>s+n(f.totalLiters),0), imp=importantAlertsDashboard(); document.getElementById("cards").innerHTML=[["Camions actifs",active],["Véhicules HS",hs],["Gasoil semaine",gasL.toFixed(1)+" L"],["AdBlue semaine",adb.reduce((s,f)=>s+n(f.totalLiters),0).toFixed(1)+" L"],["Coût semaine",(gas.concat(adb).reduce((s,f)=>s+n(f.totalCost),0)).toFixed(2)+" €"],["Conso semaine",km>0?(gasL/km*100).toFixed(2)+" L/100":"-"],["Alertes importantes",imp.length]].map(c=>`<div class="card">${c[0]}<b>${c[1]}</b></div>`).join("");}
function renderAll(){ensureAdvancedFields(); fillSelects(); installPlateSearchFuel(); installFuelAutoKmAdvanced(); renderVehicles(); renderMaintenance(); renderStock(); renderFuel(); renderAlerts(); renderDashboard(); if(document.getElementById("reports").classList.contains("active"))renderReports();}
ensureAdvancedFields(); setTimeout(()=>{try{installPlateSearchFuel();installFuelAutoKmAdvanced();renderAll();}catch(e){console.error(e)}},100);


/* ===== SAUVEGARDE CLIENT INTÉGRÉE ===== */
function installEmbeddedBackupData(){
  try{
    const keys = [
      "flotte-locale-v4-vidange-comment",
      "flotte-locale-v3-multi-edit",
      "flotte-locale-complete-v2-corrected",
      "flotte-locale-complete-v1",
      "flotte-db-v4-bilans",
      "flotte-db-v3-stock",
      "flotte-db-v2",
      "flotte-db-v3-stock",
      "flotte-db-v4-bilans",
      "flotte-locale-complete-v2-corrected"
    ];

    const hasExistingData = keys.some(k => {
      const raw = localStorage.getItem(k);
      if(!raw) return false;
      try{
        const parsed = JSON.parse(raw);
        return (parsed.fuel && parsed.fuel.length > 0) || 
               (parsed.maintenance && parsed.maintenance.length > 0) ||
               (parsed.stockMovements && parsed.stockMovements.length > 0);
      }catch(e){
        return false;
      }
    });

    if(!hasExistingData && typeof EMBEDDED_BACKUP_DATA !== "undefined"){
      db = JSON.parse(JSON.stringify(EMBEDDED_BACKUP_DATA));

      if(db.vehicles){
        db.vehicles.forEach(v=>{
          if(v.targetConso === undefined) v.targetConso = "";
          if(v.comment === undefined) v.comment = "";
        });
      }

      if(typeof normalizeFuelDates === "function") normalizeFuelDates();
      if(typeof ensureAdvancedFields === "function") ensureAdvancedFields();

      // Sauvegarde dans plusieurs clés pour rester compatible avec toutes les anciennes versions.
      localStorage.setItem("flotte-locale-v4-vidange-comment", JSON.stringify(db));
      localStorage.setItem("flotte-locale-v3-multi-edit", JSON.stringify(db));
      localStorage.setItem("flotte-locale-complete-v2-corrected", JSON.stringify(db));
      localStorage.setItem("flotte-db-v4-bilans", JSON.stringify(db));

      if(typeof renderAll === "function") renderAll();
    }
  }catch(e){
    console.error("Erreur intégration sauvegarde :", e);
  }
}

setTimeout(installEmbeddedBackupData, 100);



/* ===== MODE EN LIGNE PARTAGÉ SUPABASE =====
   Cette couche garde l'interface locale existante, mais sauvegarde aussi les données
   dans Supabase pour que plusieurs ordinateurs voient la même flotte.
*/

let ONLINE_READY = false;
let ONLINE_LOADING = false;
let ONLINE_LAST_SAVE = 0;

function getSupabaseClient(){
  try{
    if(!window.supabase || !window.SUPABASE_URL || !window.SUPABASE_ANON_KEY) return null;
    if(!window.__flotteSupabase){
      window.__flotteSupabase = window.supabase.createClient(window.SUPABASE_URL, window.SUPABASE_ANON_KEY);
    }
    return window.__flotteSupabase;
  }catch(e){
    console.error("Erreur Supabase client:", e);
    return null;
  }
}

function addOnlineStatusBar(){
  if(document.getElementById("onlineStatusBar")) return;
  const bar=document.createElement("div");
  bar.id="onlineStatusBar";
  bar.style.cssText="position:sticky;top:0;z-index:9999;padding:8px 12px;background:#fffbe6;border-bottom:1px solid #ffe58f;font-family:Arial;font-size:13px";
  bar.innerHTML='Mode en ligne : <b id="onlineStatusText">connexion...</b>';
  document.body.insertBefore(bar, document.body.firstChild);
}

function setOnlineStatus(text, ok=true){
  addOnlineStatusBar();
  const el=document.getElementById("onlineStatusText");
  if(el){
    el.textContent=text;
    el.style.color=ok ? "#238636" : "#b42318";
  }
}

async function loadSharedDataFromSupabase(){
  const client=getSupabaseClient();
  if(!client){
    setOnlineStatus("Supabase non configuré — données locales uniquement", false);
    return;
  }
  if(ONLINE_LOADING) return;
  ONLINE_LOADING=true;

  try{
    setOnlineStatus("chargement des données partagées...");
    const key=window.FLOTTE_STATE_KEY || "flotte_principale";
    const { data, error } = await client
      .from("app_state")
      .select("data")
      .eq("id", key)
      .maybeSingle();

    if(error){
      console.error(error);
      setOnlineStatus("erreur chargement Supabase", false);
      return;
    }

    if(data && data.data){
      db = data.data;
      if(typeof normalizeFuelDates === "function") normalizeFuelDates();
      if(typeof ensureAdvancedFields === "function") ensureAdvancedFields();

      // cache local de secours
      try{
        localStorage.setItem("flotte-locale-online-cache", JSON.stringify(db));
        localStorage.setItem("flotte-locale-v4-vidange-comment", JSON.stringify(db));
        localStorage.setItem("flotte-locale-v3-multi-edit", JSON.stringify(db));
      }catch(e){}

      if(typeof renderAll === "function") renderAll();
      setOnlineStatus("connecté — données partagées chargées");
    } else {
      // Premier lancement : on envoie la sauvegarde locale intégrée vers Supabase.
      await saveSharedDataToSupabase(true);
      setOnlineStatus("connecté — sauvegarde initiale envoyée");
    }

    ONLINE_READY=true;
  }catch(e){
    console.error(e);
    setOnlineStatus("erreur connexion Supabase", false);
  }finally{
    ONLINE_LOADING=false;
  }
}

async function saveSharedDataToSupabase(force=false){
  const client=getSupabaseClient();
  if(!client){
    setOnlineStatus("Supabase non configuré — sauvegarde locale uniquement", false);
    return;
  }

  const now=Date.now();
  if(!force && now - ONLINE_LAST_SAVE < 500) return;
  ONLINE_LAST_SAVE=now;

  try{
    const key=window.FLOTTE_STATE_KEY || "flotte_principale";
    const payload = {
      id: key,
      data: db,
      updated_at: new Date().toISOString()
    };

    const { error } = await client
      .from("app_state")
      .upsert(payload, { onConflict: "id" });

    if(error){
      console.error(error);
      setOnlineStatus("erreur sauvegarde Supabase", false);
    } else {
      setOnlineStatus("connecté — sauvegardé en ligne");
    }
  }catch(e){
    console.error(e);
    setOnlineStatus("erreur sauvegarde Supabase", false);
  }
}

// Remplacement de save() si elle existe déjà.
if(typeof save === "function"){
  const originalLocalSave = save;
  save = function(){
    try{
      // sauvegarde locale habituelle
      localStorage.setItem("flotte-locale-online-cache", JSON.stringify(db));
      localStorage.setItem("flotte-locale-v4-vidange-comment", JSON.stringify(db));
      localStorage.setItem("flotte-locale-v3-multi-edit", JSON.stringify(db));
    }catch(e){}
    if(typeof renderAll === "function") renderAll();
    saveSharedDataToSupabase(false);
  };
}

// Ajout d'un bouton sauvegarde forcée dans le header
function addForceOnlineSaveButton(){
  const actions=document.querySelector("header .actions") || document.querySelector(".actions");
  if(actions && !document.getElementById("forceOnlineSaveBtn")){
    const btn=document.createElement("button");
    btn.id="forceOnlineSaveBtn";
    btn.textContent="Forcer sauvegarde en ligne";
    btn.onclick=()=>saveSharedDataToSupabase(true);
    actions.appendChild(btn);
  }
}

setTimeout(()=>{
  addOnlineStatusBar();
  addForceOnlineSaveButton();
  loadSharedDataFromSupabase();
}, 300);


/* ===== AJOUT SUPPRESSION CAMION ===== */

function deleteVehicleByPlate(plate){
  if(!plate) return;

  const usedFuel = (db.fuel || []).some(f => f.plate === plate);
  const usedMaintenance = (db.maintenance || []).some(m => m.plate === plate);

  let msg = "Supprimer le camion " + plate + " du parc ?";
  if(usedFuel || usedMaintenance){
    msg += "\n\nAttention : ce camion possède déjà un historique carburant ou entretien.";
    msg += "\nLa suppression du camion ne supprime pas les anciens historiques.";
    msg += "\nIls resteront visibles dans les bilans/historiques avec cette plaque.";
  }

  if(!confirm(msg)) return;

  db.vehicles = (db.vehicles || []).filter(v => v.plate !== plate);

  if(typeof save === "function") {
    save();
  } else {
    try { localStorage.setItem("flotte-locale-online-cache", JSON.stringify(db)); } catch(e){}
    if(typeof renderAll === "function") renderAll();
    if(typeof saveSharedDataToSupabase === "function") saveSharedDataToSupabase(true);
  }
}

